import{_ as t,c as s,o as r,ah as n}from"./chunks/framework.RCw5T9E9.js";const h=JSON.parse('{"title":"Режим JSON","description":"","frontmatter":{"title":"Режим JSON"},"headers":[],"relativePath":"ru/options/json_mode.md","filePath":"ru/options/json_mode.md"}'),e={name:"ru/options/json_mode.md"};function a(g,o,i,l,d,c){return r(),s("div",null,[...o[0]||(o[0]=[n('<h1 id="json-mode-режим-просмотра-json" tabindex="-1">JSON Mode (режим просмотра JSON) <a class="header-anchor" href="#json-mode-режим-просмотра-json" aria-label="Permalink to &quot;JSON Mode (режим просмотра JSON)&quot;">​</a></h1><p>В <strong>Options → General</strong> переключатель <strong>JSON Mode</strong> задаёт реализацию <strong>просмотра и правки JSON</strong> во всём инспекторе (тела запросов и ответов во вкладке <strong>Network</strong>, тела в <strong>Mock response</strong>, снимки <strong>Pinia</strong>, данные компонента на <strong>Props</strong>, если содержимое распознаётся как JSON).</p><p>Тела <strong>не в формате JSON</strong> (XML, обычный текст и т.д.) по-прежнему открываются в <strong>одном текстовом виде</strong> с подсветкой Prism, где это поддерживается; переключатель в первую очередь влияет на работу с <strong>JSON</strong>.</p><hr><h2 id="classic" tabindex="-1">Classic <a class="header-anchor" href="#classic" aria-label="Permalink to &quot;Classic&quot;">​</a></h2><p><strong>Classic</strong> — встроенный <strong>текстовый редактор с подсветкой Prism</strong> (<code>JsonTextEditor</code>):</p><ul><li>Одна <strong>текстовая</strong> область — <strong>отдельного древовидного интерфейса нет</strong>.</li><li>В режиме <strong>только чтение</strong> включается подсветка JSON (и других поддерживаемых языков).</li><li>Учтены <strong>большие фрагменты</strong>: после порога размера подсветка ослабевается, чтобы не подвешивать интерфейс; для очень больших <strong>не-JSON</strong> полей только чтения может использоваться облегчённый просмотрщик.</li></ul><p>Выбирайте Classic, если нужен <strong>минимальный и быстрый текстовый</strong> режим.</p><hr><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><p><strong>Advanced</strong> — <strong><code>vanilla-jsoneditor</code></strong> (компонент <code>JsonEditor</code> в интерфейсе):</p><ul><li><strong>Два представления одного и того же JSON</strong>: <strong>Text</strong> (код) и <strong>Tree</strong> (структура). Переключение — на панели редактора; последний выбор (<strong>Text</strong> или <strong>Tree</strong>) <strong>сохраняется</strong> в настройках (<code>json.mode</code>).</li><li><strong>Режим Text</strong>: инструменты форматирования (например <strong>Format</strong> / <strong>Compact</strong>, где разрешено редактирование), <strong>Undo / Redo</strong>, <strong>Поиск</strong>, копирование и прочие возможности библиотеки.</li><li><strong>Режим Tree</strong>: свёртка/развёртка узлов, <strong>хлебные крошки / путь</strong> в документе, контекстные меню по узлам, а также связанные с деревом сценарии сортировки и правки, которые добавляет приложение.</li></ul><p>Выбирайте Advanced, если нужны <strong>дерево</strong>, <strong>история правок</strong>, <strong>поиск</strong> и более богатое редактирование JSON.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/ru/options/customize.html">Персонализация</a> — остальные настройки <strong>General</strong> (тема, фон, сохранённые файлы).</li><li><a href="/qa-tools/docs/ru/options/display_mode.html">Режимы отображения</a> — как показывается панель инспектора на странице.</li></ul>',16)])])}const m=t(e,[["render",a]]);export{h as __pageData,m as default};
